        {"title": "实现TPS计算器", "description": "编写函数calculate_tps(total_transactions, duration_seconds)，计算TPS。\n\nTPS = total_transactions / duration_seconds", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "easy", "category": "性能测试", "knowledge_point": "性能指标", "code_template": "def calculate_tps(total_transactions, duration_seconds):\n    pass", "test_cases": "[{\"input\": \"1000, 10\", \"expected\": \"100.0\"}]", "solution": "def calculate_tps(total_transactions, duration_seconds):\n    if duration_seconds == 0: return 0\n    return round(total_transactions / duration_seconds, 2)", "hint": "注意除零保护"},
